changeSet.sql:
CREATE TABLE news
(
id serial,
title character varying (255) DEFAULT NULL,
description text DEFAULT NULL,
news_url character varying (255) DEFAULT NULL,
date_of_news timestamp without time zone NOT NULL DEFAULT now(),
expired_date timestamp without time zone NOT NULL DEFAULT now(),
created_at timestamp without time zone NOT NULL DEFAULT now(),
updated_at timestamp without time zone NOT NULL DEFAULT now(),

CONSTRAINT pk_news_id PRIMARY KEY (id)
);
CREATE INDEX i_news_title ON news (title);
CREATE INDEX i_news_description ON news (description);
CREATE INDEX i_news_url ON news (news_url);
CREATE INDEX i_date_of_news ON news (date_of_news);
CREATE INDEX i_news_expired_date ON news (expired_date);
CREATE INDEX i_news_created_at ON news (created_at);
CREATE INDEX i_news_updated_at ON news (updated_at);

