CONSTRAINT pk_webinar_id PRIMARY KEY (id)
);
CREATE INDEX i_webinar_title ON webinars (title);
CREATE INDEX i_webinar_description ON webinars (description);
CREATE INDEX i_webinar_url ON webinars (webinar_url);
CREATE INDEX i_date_of_webinar ON webinars (date_of_webinar);
CREATE INDEX i_webinar_expired_date ON webinars (expired_date);
CREATE INDEX i_webinar_created_at ON webinars (created_at);
CREATE INDEX i_webinar_updated_at ON webinars (updated_at);

